(() => {

const dt = $('GET Booking Details').item.json.starts_at
  .toDateTime()
  .setZone("America/Sao_Paulo")

const now = DateTime.now().setZone("America/Sao_Paulo")

const sameDay = dt.hasSame(now, "day")

const tomorrow = dt.hasSame(now.plus({ days: 1 }), "day")

const sameWeek =
  dt.weekNumber === now.weekNumber &&
  dt.year === now.year

const nextWeek =
  dt.weekNumber === now.plus({ weeks: 1 }).weekNumber &&
  dt.year === now.plus({ weeks: 1 }).year

const base =
  dt.setLocale("pt-BR")
    .toFormat("cccc, dd/MM 'às' HH'h'mm")
    .replace("-feira","")

if (sameDay) {
  return "hoje, " + dt.toFormat("dd/MM 'às' HH'h'mm")
}

if (tomorrow) {
  return "amanhã, " + dt.toFormat("dd/MM 'às' HH'h'mm")
}

if (nextWeek) {
  return "" + base
}

return base

})()
}}, com duração de 25 minutos.

