function removeEmpty(value) {
  if (Array.isArray(value)) {
    return value
      .map(removeEmpty)
      .filter(v => v !== null && v !== undefined && v !== '');
  }

  if (value && typeof value === 'object') {
    const out = {};
    for (const [key, val] of Object.entries(value)) {
      const cleaned = removeEmpty(val);

      if (cleaned === null || cleaned === undefined || cleaned === '') continue;
      if (Array.isArray(cleaned) && cleaned.length === 0) continue;
      if (
        typeof cleaned === 'object' &&
        !Array.isArray(cleaned) &&
        Object.keys(cleaned).length === 0
      ) continue;

      out[key] = cleaned;
    }
    return out;
  }

  return value;
}

const baseItem = $('Hidrata Memória SQL').first().json;
const histItem = $json || {};

const output = {
  ...baseItem,

  message: {
    ...baseItem.message,
    content:
      histItem?.message?.content ||
      histItem?.message ||
      histItem?.last_user_message ||
      baseItem?.message?.content ||
      '',
    historico:
      histItem?.message?.historico ||
      histItem?.source ||
      'atual'
  },

  inputs: {
    ...(baseItem.inputs || {}),
    ...(histItem.inputs || {}),
    booking_link:
      (baseItem.inputs && baseItem.inputs.booking_link) ||
      'https://agenda.convertix.app/r1'
  }
};

return [{ json: removeEmpty(output) }];

function removeEmpty(value) {
  if (Array.isArray(value)) {
    return value
      .map(removeEmpty)
      .filter(v => v !== null && v !== undefined && v !== '');
  }

  if (value && typeof value === 'object') {
    const out = {};
    for (const [key, val] of Object.entries(value)) {
      const cleaned = removeEmpty(val);

      if (cleaned === null || cleaned === undefined || cleaned === '') continue;
      if (Array.isArray(cleaned) && cleaned.length === 0) continue;
      if (
        typeof cleaned === 'object' &&
        !Array.isArray(cleaned) &&
        Object.keys(cleaned).length === 0
      ) continue;

      out[key] = cleaned;
    }
    return out;
  }

  return value;
}

function parseJsonSafe(value) {
  if (!value) return value;
  if (typeof value === 'object') return value;

  try {
    return JSON.parse(value);
  } catch {
    return value;
  }
}

const baseItem = $('Mensagem interpretada').first().json;
const memoryRaw = $('MEMORY').first()?.json.memory || {};

// LEAD
const hydratedLead = removeEmpty({
  ...baseItem.lead,
  sender_name: baseItem.lead?.sender_name || memoryRaw.name || '',
  phone: baseItem.lead?.phone || memoryRaw.phone || '',
  entry_channel: baseItem.lead?.entry_channel || memoryRaw.entry_channel || '',
  utms: baseItem.lead?.utms || parseJsonSafe(memoryRaw.utms) || {},
  sender_type: baseItem.lead?.sender_type || '',
  company_name: baseItem.lead?.company_name || memoryRaw.company_name || '',
  instagram: baseItem.lead?.instagram || memoryRaw.instagram || '',
  website: baseItem.lead?.website || memoryRaw.website || '',
  google_business_profile:
    baseItem.lead?.google_business_profile || memoryRaw.google_business_profile || ''
});

// CHATWOOT
const hydratedChatwoot = removeEmpty({
  ...baseItem.chatwoot,
  account_id: baseItem.chatwoot?.account_id || memoryRaw.account_id || '',
  contact_id: baseItem.chatwoot?.contact_id || memoryRaw.contact_id || '',
  conversation_id: baseItem.chatwoot?.conversation_id || memoryRaw.conversation_id || '',
  message_id: baseItem.chatwoot?.message_id || '',
  labels: baseItem.chatwoot?.labels || [],
  system_event: baseItem.chatwoot?.system_event || '',
  event: baseItem.chatwoot?.event || '',
  dify_uuid: baseItem.chatwoot?.dify_uuid || memoryRaw.dify_uuid || ''
});

// AGENDA separado
const agenda = removeEmpty({
  selected_option: baseItem.inputs?.agenda?.selected_option || memoryRaw.selected_option || '',
  selected_option_start: baseItem.inputs?.agenda?.selected_option_start || memoryRaw.selected_option_start || '',
  option_1_start: baseItem.inputs?.agenda?.option_1_start || memoryRaw.option_1_start || '',
  option_2_start: baseItem.inputs?.agenda?.option_2_start || memoryRaw.option_2_start || '',
  requested_day: baseItem.inputs?.agenda?.requested_day || memoryRaw.requested_day || '',
  requested_date: baseItem.inputs?.agenda?.requested_date || memoryRaw.requested_date || '',
  requested_period: baseItem.inputs?.agenda?.requested_period || memoryRaw.requested_period || '',
  requested_time_min: baseItem.inputs?.agenda?.requested_time_min || memoryRaw.requested_time_min || '',
  requested_time_max: baseItem.inputs?.agenda?.requested_time_max || memoryRaw.requested_time_max || '',
  email: baseItem.inputs?.agenda?.email || memoryRaw.email || '',
  agenda_reply_type: baseItem.inputs?.agenda?.agenda_reply_type || ''
});

// INPUTS
const hydratedInputs = removeEmpty({
  ...(baseItem.inputs || {}),

  lead_status: baseItem.inputs?.lead_status || memoryRaw.lead_status || '',
  last_intent: baseItem.inputs?.last_intent || memoryRaw.last_intent || '',
  lead_summary: baseItem.inputs?.lead_summary || parseJsonSafe(memoryRaw.lead_summary) || {},
  last_user_message: baseItem.inputs?.last_user_message || memoryRaw.last_user_message || '',
  last_ai_message: baseItem.inputs?.last_ai_message || memoryRaw.last_ai_message || '',
  memory_system_event: baseItem.inputs?.memory_system_event || memoryRaw.system_event || '',

  agenda
});

// SCORE separado
const score = removeEmpty({
  lead_score: memoryRaw.lead_score,
  lead_temperature: memoryRaw.lead_temperature,
  score_estrutura: memoryRaw.score_estrutura,
  score_potencial_comercial: memoryRaw.score_potencial_comercial,
  score_execucao: memoryRaw.score_execucao,
  score_investimento: memoryRaw.score_investimento,
  score_conversa: memoryRaw.score_conversa,
  score_bonus: memoryRaw.score_bonus,
  score_penalty: memoryRaw.score_penalty
});

const output = removeEmpty({
  ...baseItem,
  lead: hydratedLead,
  chatwoot: hydratedChatwoot,
  inputs: hydratedInputs,
  score
});

return [{ json: output }];

const msg = String(
  $json.inputs?.interpreted_message ||
  $json.message?.content ||
  $json.inputs?.last_user_message ||
  ''
).toLowerCase().trim();

const leadStatus = String($json.inputs?.lead_status || '');
const lastIntent = String($json.inputs?.last_intent || '');
const memorySystemEvent = String($json.inputs?.memory_system_event || '');

let agenda_reply_type = 'UNKNOWN';
let requested_day = '';
let requested_period = '';
let requested_time_min = '';
let requested_time_max = '';

const isAgendaFlow =
  [
    'AGUARDANDO_ESCOLHA_HORARIO',
    'SOLICITAR_NOVAS_OPCOES'
  ].includes(leadStatus) ||
  lastIntent === 'HORARIOS_ENVIADOS' ||
  memorySystemEvent === 'HORARIOS_ENVIADOS';

if (isAgendaFlow) {
  if (/(primeira opção|primeira opcao|opção 1|opcao 1|segunda opção|segunda opcao|opção 2|opcao 2)\b/i.test(msg)) {
    agenda_reply_type = 'OPTION_SELECTION';
  } else if (/(não tenho interesse|nao tenho interesse|não quero agendar|nao quero agendar|pode encerrar|não quero mais|nao quero mais)/i.test(msg)) {
    agenda_reply_type = 'REAL_MEETING_REJECTION';
  } else if (/^(não obrigado|nao obrigado|não|nao|deixa pra lá|deixa pra la)$/i.test(msg)) {
    agenda_reply_type = 'AMBIGUOUS_NEGATIVE';
  } else if (/(nenhum desses|nenhuma dessas|esses horários não|esses horarios nao|outro horário|outro horario|não consigo nesses|nao consigo nesses|pode ser outro|tem outro)/i.test(msg)) {
    agenda_reply_type = 'REJECTED_OPTIONS';
  } else if (/(segunda|terça|terca|quarta|quinta|sexta|sábado|sabado|domingo|\b\d{1,2}h\b|\b\d{1,2}:\d{2}\b|manhã|manha|tarde|noite)/i.test(msg)) {
    agenda_reply_type = 'NEW_TIME_REQUEST';
  }

  if (/segunda/.test(msg)) requested_day = 'segunda';
  if (/terça|terca/.test(msg)) requested_day = 'terça';
  if (/quarta/.test(msg)) requested_day = 'quarta';
  if (/quinta/.test(msg)) requested_day = 'quinta';
  if (/sexta/.test(msg)) requested_day = 'sexta';
  if (/sábado|sabado/.test(msg)) requested_day = 'sábado';
  if (/domingo/.test(msg)) requested_day = 'domingo';

  if (/manhã|manha/.test(msg)) requested_period = 'manha';
  if (/tarde/.test(msg)) requested_period = 'tarde';
  if (/noite/.test(msg)) requested_period = 'noite';

  const timeMatch = msg.match(/\b(\d{1,2})h(?:(\d{2}))?\b|\b(\d{1,2}):(\d{2})\b/);

  if (timeMatch) {
    const hh = timeMatch[1] || timeMatch[3];
    const mm = timeMatch[2] || timeMatch[4] || '00';
    requested_time_min = `${String(hh).padStart(2, '0')}:${String(mm).padStart(2, '0')}:00`;
    requested_time_max = requested_time_min;
  }
}

return [
  {
    json: {
      ...$json,
      inputs: {
        ...($json.inputs || {}),
        agenda: {
          ...($json.inputs?.agenda || {}),
          agenda_reply_type,
          requested_day,
          requested_period,
          requested_time_min,
          requested_time_max
        }
      }
    }
  }
];
